async (page) => {
  var title = "图解 Blaze · Ch.01 全景概览 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 1 章 · 全景概览</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">JPA 增强 · 类型安全 · Entity View · CriteriaBuilder · 框架对比</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">\n      JPA 是 Java 持久化的标准，但当查询复杂度上升——子查询嵌套、CTE、窗口函数、DTO 投影——标准 Criteria API 就变得力不从心。\n      Blaze-Persistence 正是为填补这一空白而生的开源框架：它在 JPA 之上构建了一套<strong style=\"color:#1a1a2e;font-weight:700;\">类型安全、表达力极强</strong>的查询 DSL，\n      同时通过 <em>Entity View</em> 将 DTO 映射提升到声明式水平。本章带你从全局视角了解 Blaze-Persistence 的定位、架构与核心概念。\n    </p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">理解 JPA Criteria API 的局限性以及 Blaze-Persistence 的解决思路</li><li style=\"margin-bottom:4px;font-size:13px;\">掌握 Core / Entity View / 集成层 的三层架构</li><li style=\"margin-bottom:4px;font-size:13px;\">认识 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 等核心接口</li><li style=\"margin-bottom:4px;font-size:13px;\">在 JPA Criteria、QueryDSL、jOOQ 之间做出合理技术选型</li><li style=\"margin-bottom:4px;font-size:13px;\">了解 JPQL 生成管线的完整流程</li><li style=\"margin-bottom:4px;font-size:13px;\">提前知晓常见陷阱与限制</li></ul></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">1.1 JPA 的困境与 Blaze-Persistence 的诞生</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    JPA（Java Persistence API）通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityManager</code> 和 JPQL 为 Java 应用提供了统一的 ORM 层。\n    对于简单的 CRUD 操作，JPA 工作得很好。但一旦需求演变为：\n  </p></section>\n<section><ul style=\"margin:0 0 12px 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\"><li style=\"margin-bottom:4px;\">多层嵌套子查询与关联过滤</li><li style=\"margin-bottom:4px;\">CTE（公用表表达式）递归查询</li><li style=\"margin-bottom:4px;\">窗口函数（<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ROW_NUMBER</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RANK</code>）</li><li style=\"margin-bottom:4px;\">批量 UPDATE / DELETE 的 DML 语句</li><li style=\"margin-bottom:4px;\">高效 DTO 投影（避免 N+1 和全字段加载）</li></ul></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    标准 JPA Criteria API 就暴露出冗长、类型不安全、SQL 功能覆盖不足等问题。\n  </p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ JPA 困境与 Blaze-Persistence 的定位</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Blaze</p></section></td><td style=\"padding:0 2px;text-align:center;vertical-align:middle;width:24px;\"><p style=\"margin:0;font-size:18px;color:#1e6fff;line-height:1;\">→</p></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">Persistence</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">🗄️ 业务需求<br/>复杂查询</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">📜 JPA Criteria API</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">⚠️ 冗长的代码</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">⚠️ 缺少 CTE / 窗口函数</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">⚠️ DTO 投影困难</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">🚀 Blaze-Persistence</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">✅ 类型安全 DSL</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">✅ CTE + 窗口函数</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">✅ Entity View 投影</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">代码对比：同一查询的两种写法</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    假设我们需要查询\"年龄大于 18 且姓名以 'J' 开头的用户，并按注册时间降序排列\"。\n    来看看 JPA Criteria API 和 Blaze-Persistence CriteriaBuilder 的差异。\n  </p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder cb = em.getCriteriaBuilder();<br/>CriteriaQuery&lt;User&gt; cq = cb.createQuery(User.class);<br/>Root&lt;User&gt; root = cq.from(User.class);<br/><br/>Predicate agePred = cb.greaterThan(<br/>    root.get(\"age\"), 18);<br/>Predicate namePred = cb.like(<br/>    root.get(\"name\"), \"J%\");<br/><br/>cq.where(cb.and(agePred, namePred));<br/>cq.orderBy(cb.desc(<br/>    root.get(\"registeredAt\")));<br/><br/>List&lt;User&gt; users = em<br/>    .createQuery(cq)<br/>    .getResultList();</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;User&gt; cb = cbf<br/>    .create(em, User.class);<br/><br/>List&lt;User&gt; users = cb<br/>    .where(\"age\").gt(18)<br/>    .where(\"name\").like().value(\"J%\")<br/>    .orderByDesc(\"registeredAt\")<br/>    .getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 关键洞察</strong><br/>\n    Blaze-Persistence 的 CriteriaBuilder 通过流式 API（Fluent API）将查询构建代码量减少 60%–70%，\n    同时保留完整的类型安全。每一个方法调用对应一个 SQL 子句，阅读和维护成本大幅降低。\n  </section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ JPA Criteria vs Blaze-Persistence 代码行数对比</p><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">❌ JPA Criteria API — 6 步</span> <span style=\"color:#2b2b2b;\">1. CriteriaBuilder 获取↓2. CriteriaQuery 创建↓3. Root 定义↓4. Predicate 逐个构建↓5. 组合 where / orderBy↓6. 执行查询</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(63,185,80);border-left:3px solid #3fb950;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#3fb950;\">✅ Blaze-Persistence — 4 步</span> <span style=\"color:#2b2b2b;\">1. cbf.create()↓2. .where().gt() / .like()↓3. .orderByDesc()↓4. .getResultList()</span></p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">1.2 架构分层：Core + Entity View + 集成层</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    Blaze-Persistence 的设计采用清晰的分层架构。每一层只依赖下方的层，上层可以选择性使用。\n    理解这个分层是掌握框架的第一步。\n  </p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ Blaze-Persistence 四层架构</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n🔗 集成层 Integration\n\nSpring Data\nDeltaSpike\nJAX-RS\nGraphQL\n\n\n▼\n\n📐 Entity View\n\nDTO 投影\nUpdatable Views\nCreatable Views\n\n\n▼\n\n⚙️ Blaze-Persistence Core\n\nCriteriaBuilder\nCTE 支持\n窗口函数\n批量 DML\n\n\n▼\n\n🏗️ JPA Provider\n\nHibernate\nEclipseLink\nDataNucleus\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">各层职责</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">层级</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">模块</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">核心职责</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JPA Provider</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">javax.persistence</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">jakarta.persistence</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">提供底层 ORM 实现，将 JPQL 翻译为原生 SQL 并管理实体生命周期</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Core</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-core</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">类型安全的 CriteriaBuilder API，扩展 JPA 不支持的 SQL 特性（CTE、窗口函数、集合操作、批量 DML）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Entity View</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-entity-view</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">声明式 DTO 投影框架，通过注解定义视图接口，自动生成优化的 JPQL <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT</code> 子句</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">集成层</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">blaze-persistence-integration-*</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">与 Spring Data、DeltaSpike Data、JAX-RS、GraphQL 等上层框架集成，提供 Repository 抽象和自动分页</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📌 按需引入</strong><br/>\n    如果你只需要增强的 CriteriaBuilder，只引入 Core 即可。Entity View 和集成层是可选的，按需添加 Maven/Gradle 依赖。\n  </section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 模块依赖关系</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">spring</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">data</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">entity</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">view</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">impl</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">api</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">hibernate</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">integration</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">📱 你的应用</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">spring-data-integration</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">entity-view-impl</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core-impl</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">core-api / SPI</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">hibernate-integration</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JPA Provider</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">1.3 核心概念速览</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    在深入各模块之前，先建立对核心接口和注解的整体认知。Blaze-Persistence 的 API 围绕两个工厂展开：\n  </p></section>\n<section><ul style=\"margin:0 0 12px 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\"><li style=\"margin-bottom:4px;\"><strong style=\"color:#1a1a2e;font-weight:700;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code></strong>（CBF）— 创建查询构建器，是 Core 层的入口</li><li style=\"margin-bottom:4px;\"><strong style=\"color:#1a1a2e;font-weight:700;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code></strong>（EVM）— 管理 Entity View 的注册与实例化，是 Entity View 层的入口</li></ul></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 核心接口关系类图</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CriteriaBuilderFactory</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">create · startSet</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">EntityViewManager</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">find · applySetting · save</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">核心注解一览</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    Entity View 通过 Java 接口 + 注解实现声明式 DTO 定义。以下是最常用的注解：\n  </p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">注解</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">位置</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">用途</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">接口/抽象类</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">标记该类型为某个实体的视图（DTO 定义的入口）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@IdMapping</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">getter 方法</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">映射实体的主键字段</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping(\"expr\")</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">getter 方法</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">映射任意 JPQL 表达式到视图属性</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@UpdatableEntityView</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">接口/抽象类</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">允许通过视图执行 UPDATE 操作</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@CreatableEntityView</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">接口/抽象类</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">允许通过视图创建新实体</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingSubquery</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">getter 方法</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">将子查询结果映射为视图属性</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">getter 方法</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">关联查询映射，支持自定义关联策略</td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Entity View 示例</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(User.class)<br/>public interface UserSummaryView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    String getName();<br/><br/>    @Mapping(\"SIZE(orders)\")<br/>    long getOrderCount();<br/><br/>    @Mapping(\"TREAT(address AS DomesticAddress).city\")<br/>    String getCity();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 使用</span><br/>CriteriaBuilder&lt;User&gt; cb = cbf.create(em, User.class);<br/>List&lt;UserSummaryView&gt; views = evm<br/>    .applySetting(EntityViewSetting.create(UserSummaryView.class), cb)<br/>    .getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 关键洞察</strong><br/>\n    Entity View 的核心优势在于<strong style=\"color:#1a1a2e;font-weight:700;\">只 SELECT 视图中声明的字段</strong>。上例生成的 JPQL 不会加载 User 的所有列，\n    而是精确投影 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">id</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">name</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SIZE(orders)</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">address.city</code>，\n    从根本上避免了全字段加载的性能浪费。\n  </section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ Entity View 工作流</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">JPA Provider</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">1.4 与同类框架对比</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    Java 生态中，处理复杂查询的框架不止 Blaze-Persistence。以下从多个维度进行横向比较，\n    帮助你在技术选型时做出明智决策。\n  </p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 四大查询框架能力雷达</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n\n高 JPA 集成 ↑\n\n\n\n低 SQL 覆盖 ← → 高 SQL 覆盖\n\n\n\nJPA 友好但 SQL 受限\n\nJPA Criteria\n\n\n\nJPA 友好 + SQL 强大\n\n★ Blaze-Persistence\n\n\nQueryDSL\n\n\n\n脱离 JPA + SQL 受限\n（无代表框架）\n\n\n脱离 JPA + SQL 强大\n\njOOQ\n\n\n\n\n</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">维度</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">JPA Criteria</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">QueryDSL</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">jOOQ</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Blaze-Persistence</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">类型安全</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">部分（Metamodel 生成）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 强（Q 类生成）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 强（代码生成）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 强（流式 API）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">SQL 功能覆盖</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌ 有限（无 CTE / 窗口函数）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 中等</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 完整（原生 SQL）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 广泛（CTE / 窗口 / 集合操作）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">DTO 投影</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 手动构造</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ Projection 半自动</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ Record Mapper</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ Entity View 声明式</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JPA 集成</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 原生</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ JPA 模块</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌ 独立于 JPA</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 构建于 JPA 之上</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Keyset 分页</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 手动实现</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 内置支持</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">学习曲线</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">中等</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">低</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">中等</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">中等偏高</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">社区活跃度</strong></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">JPA 标准，无独立社区</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 维护放缓</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 商业支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 中等（Blazebit 团队）</td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">何时选择 Blaze-Persistence？</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 技术选型决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Blaze</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Persistence</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要 JPA 集成？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要 CTE / 窗口函数？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 需要声明式<br/>DTO 投影？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 现有 QueryDSL<br/>能满足需求？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 选择<br/>Blaze-Persistence</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">推荐 jOOQ</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">可继续使用<br/>QueryDSL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JPA Criteria<br/>或 QueryDSL</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📌 选型建议</strong><br/>\n    如果你的项目已经深度依赖 JPA/Hibernate，且面临复杂查询和高效 DTO 投影的双重需求，\n    Blaze-Persistence 是目前最优解。如果你不需要 JPA（例如纯 JDBC 项目），jOOQ 是更好的选择。\n  </section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">1.5 JPQL 生成管线</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    Blaze-Persistence 不直接生成原生 SQL，而是先生成增强的 JPQL（兼容 HQL），再委托给 JPA Provider 翻译为具体数据库的 SQL。\n    理解这条管线有助于排查性能问题和理解框架行为。\n  </p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ JPQL 生成管线全流程</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">🧑‍💻 应用代码<br/>CriteriaBuilder API</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">🌳 表达式树<br/>ExpressionTree</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">📝 JPQL 渲染器<br/>JpqlRenderer</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">🔌 JPA Provider<br/>Hibernate / EclipseLink</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">🗃️ 原生 SQL<br/>PostgreSQL / MySQL / ...</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">📊 数据库<br/>执行查询</p></section></td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">管线各阶段详解</h3></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">1</span></p><p style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">API 调用 → 表达式树</p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n          每一次 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.where()</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.orderBy()</code>、<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">.select()</code> 调用，\n          都会在内部构建一棵<strong style=\"color:#1a1a2e;font-weight:700;\">表达式树</strong>（AST）。树的节点包括：谓词节点、路径表达式、函数调用、子查询引用等。\n        </p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">2</span></p><p style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">表达式树优化</p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n          框架在渲染前会对表达式树做优化：合并冗余 JOIN、提取公共子表达式、决定是否使用子查询或 EXISTS 改写。\n        </p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">3</span></p><p style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">JPQL 渲染</p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlRenderer</code> 遍历表达式树，生成标准 JPQL 字符串。对于 JPA 不支持的特性（CTE、窗口函数），\n          框架会生成<strong style=\"color:#1a1a2e;font-weight:700;\">扩展 JPQL</strong>或直接注入原生 SQL 片段。\n        </p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">4</span></p><p style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">JPA Provider 翻译</p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n          Hibernate 或 EclipseLink 接收 JPQL，经过其内部解析器和方言（Dialect）转换为目标数据库的原生 SQL。\n        </p></section>\n<section style=\"margin:16px 0;padding:14px 16px;background:#f5f5f5;border-radius:8px;border:1px solid #e5e7eb;\"><p style=\"margin:0 0 8px;\"><span style=\"display:inline-block;width:28px;height:28px;background:#1e6fff;color:#fff;border-radius:50%;text-align:center;line-height:28px;font-weight:700;font-size:14px;\">5</span></p><p style=\"font-size:15px;font-weight:600;color:#1e6fff;margin:18px 0 8px;\">数据库执行</p><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">原生 SQL 被发送到数据库，返回 ResultSet，再经由 JPA Provider 映射回 Java 对象。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 表达式树示例（WHERE age > 18 AND name LIKE 'J%'）</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">user</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">age</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">name</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">AND</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">GT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">LIKE</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpr<br/>user.age</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Literal<br/>18</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">PathExpr<br/>user.name</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Literal<br/>'J%'</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:8px;padding:14px 16px;margin:14px 0 20px;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;letter-spacing:.5px;margin-bottom:8px;\">🔍 实战案例</p><p style=\"font-size:14px;font-weight:600;color:#1e6fff;margin:0 0 6px;\">调试技巧：查看生成的 JPQL</p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;line-height:1.7;\">在开发阶段，可以通过以下方式查看 Blaze-Persistence 生成的 JPQL：</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;User&gt; cb = cbf.create(em, User.class)<br/>    .where(\"age\").gt(18);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 获取生成的 JPQL 字符串</span><br/>String jpql = cb.getQueryString();<br/>System.out.println(jpql);<br/><span style=\"color:#6c7086;font-style:italic;\">// 输出: SELECT user FROM User user WHERE user.age &gt; :param_0</span></p><p style=\"font-size:13px;color:#2b2b2b;margin-bottom:6px;line-height:1.7;\">配合 Hibernate 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">hibernate.show_sql=true</code> 可以同时看到最终的原生 SQL。</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">1.6 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    任何框架都有边界。提前了解 Blaze-Persistence 的限制，可以避免在项目后期踩坑。\n  </p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 陷阱全景图</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">root((\"⚠️ 陷阱与限制\"</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">JPA Provider 依赖</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">Hibernate 支持最完整</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">EclipseLink 部分功能受限</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">DataNucleus 实验性支持</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">SQL 特性覆盖</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">CTE 支持因数据库而异</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">窗口函数需数据库原生支持</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">某些方言生成的 SQL 不够优化</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">Entity View</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">注解学习曲线较陡</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">复杂映射调试困难</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">循环引用需特殊处理</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">运行时</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">JPQL 解析有额外开销</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">首次查询需预热</p><p style=\"margin:1px 0;padding:3px 8px 3px 0px;font-size:14px;font-weight:700;color:#1e6fff;border-left:2px solid #1e6fff22;\">升级 Hibernate 版本需验证兼容性</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">1.6.1 JPA Provider 兼容性</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n    Blaze-Persistence 虽然基于 JPA 标准，但内部大量使用了 Provider 特定的扩展能力。\n    各 Provider 的支持程度不同：\n  </p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">特性</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Hibernate</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">EclipseLink</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">DataNucleus</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">CriteriaBuilder 基础</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 完整</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 完整</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 基本</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">CTE（WITH 子句）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">窗口函数</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 部分</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">LATERAL JOIN</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Entity View</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 完整</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 完整</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 基本</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">批量 DML（INSERT / UPDATE）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 部分</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">集合操作（UNION / INTERSECT）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 部分</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">❌</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">⚠️ 警告</strong><br/>\n    如果你的项目不使用 Hibernate，请在选型前仔细评估目标 Provider 对所需特性的支持程度。\n    EclipseLink 用户在使用 CTE 和窗口函数时会遇到不可绕过的限制。\n  </section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">1.6.2 数据库方言差异</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 各数据库对高级 SQL 特性的支持</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n✅ 完整支持\nPostgreSQL<br/>SQL Server<br/>Oracle\n\n\n⚠️ 部分支持\nMySQL 8+<br/>MariaDB 10.2+\nCTE 可用，递归受限\n\n\n❌ 受限\nH2<br/>HSQLDB\n不支持递归 CTE\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">1.6.3 Entity View 常见陷阱</h3></section>\n<section><ul style=\"margin:0 0 12px 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\"><li style=\"margin-bottom:4px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">循环引用</strong>：A View 引用 B View，B View 又引用 A View → 需要用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingCorrelated</code> 或拆分子视图打破循环</li><li style=\"margin-bottom:4px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">延迟加载误区</strong>：Entity View 默认即时加载所有声明的属性，不存在 JPA 实体的 LAZY 语义</li><li style=\"margin-bottom:4px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">集合映射性能</strong>：在 View 中映射 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Set<SubView></code> 时，如果数据量大，要配合分页或限制条数</li><li style=\"margin-bottom:4px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">更新冲突</strong>：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@UpdatableEntityView</code> 使用乐观锁，需要实体定义 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Version</code> 字段</li></ul></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">💡 最佳实践</strong><br/>\n    在项目初期使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">cb.getQueryString()</code> 配合 SQL 日志验证每一个关键查询的生成结果。\n    不要等到上线才发现生成的 SQL 不符合预期。第 2 章将详细介绍如何配置日志级别以便调试。\n  </section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">1.6.4 性能注意事项</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">▸ 性能影响因素与应对策略</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">性能关注点</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JPQL 解析开销</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">首次查询预热</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Entity View 实例化</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">生成 SQL 质量</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">🛡️ 启用查询缓存</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">🛡️ 应用启动时预热</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">🛡️ 使用接口而非抽象类</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">🛡️ 检查执行计划</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\">JPA Criteria API 在复杂查询场景下存在冗长、类型安全不足、SQL 功能覆盖有限等问题</li><li style=\"margin-bottom:5px;font-size:14px;\">Blaze-Persistence 通过 <strong style=\"color:#1a1a2e;font-weight:700;\">Core（CriteriaBuilder）</strong>和 <strong style=\"color:#1a1a2e;font-weight:700;\">Entity View</strong> 两大模块分别解决了查询构建和 DTO 投影的痛点</li><li style=\"margin-bottom:5px;font-size:14px;\">框架采用四层架构：JPA Provider → Core → Entity View → 集成层，各层职责清晰、按需引入</li><li style=\"margin-bottom:5px;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 是框架的两大入口</li><li style=\"margin-bottom:5px;font-size:14px;\">与 QueryDSL、jOOQ 相比，Blaze-Persistence 在\"JPA 集成 + 高级 SQL 特性\"这一象限具有独特优势</li><li style=\"margin-bottom:5px;font-size:14px;\">JPQL 生成管线经历：API 调用 → 表达式树 → JPQL 渲染 → JPA Provider 翻译 → 原生 SQL</li><li style=\"margin-bottom:5px;font-size:14px;\">Hibernate 是最佳 JPA Provider；使用 EclipseLink 或 DataNucleus 时需评估特性支持</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 2 章 · 项目搭建</span> 将介绍如何从零搭建 Blaze-Persistence 项目，初始化 CriteriaBuilderFactory 与 EntityViewManager。</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}